import{_ as l,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/Bun-开发工具.md","filePath":"github汇总/开发工具/Bun-开发工具.md"}'),n={name:"github汇总/开发工具/Bun-开发工具.md"};function o(d,a,h,c,t,s){return e(),i("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Bun</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>oven-sh</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>JavaScript和TypeScript开发中使用Node.js存在启动时间长、内存占用高、需要安装多个工具（运行时、打包器、测试运行器、包管理器）等问题，导致开发效率低下。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><p>一个面向JavaScript和TypeScript的全能开发工具包，包含运行时、打包器、测试运行器和包管理器。</p><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ol><li>用Zig语言编写，基于JavaScriptCore，速度极快</li><li>启动时间短，内存占用少</li><li>内置测试运行器、脚本运行器和兼容Node.js的包管理器，一个工具顶多个</li><li>支持Linux、macOS和Windows跨平台</li><li>对现有Node.js项目几乎无需修改即可使用，切换成本低</li></ol><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/oven-sh/bun" target="_blank" rel="noreferrer">https://github.com/oven-sh/bun</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于前端开发者、Node.js开发者，支持Linux（x64 &amp; arm64）、macOS（x64 &amp; Apple Silicon）、Windows（x64 &amp; arm64）。Linux用户强烈建议内核版本5.6或更高，最低5.1。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li><p>检查操作系统版本：</p><ul><li>执行位置：本机终端</li><li>完整命令：<code>uname -a</code>（Linux/macOS）或 <code>winver</code>（Windows）</li><li>成功标志：显示系统版本信息</li><li>失败处理：确认系统是否在支持列表中</li></ul></li><li><p>检查是否已安装其他Node.js环境（可选）：</p><ul><li>执行位置：本机终端</li><li>完整命令：<code>node -v</code></li><li>成功标志：显示Node.js版本号（如果已安装）</li><li>失败处理：无Node.js环境也可以直接安装Bun</li></ul></li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="步骤1-安装bun" tabindex="-1">步骤1：安装Bun <a class="header-anchor" href="#步骤1-安装bun" aria-label="Permalink to “步骤1：安装Bun”">​</a></h3><ul><li>步骤目标：在系统上安装Bun</li><li>执行位置：本机终端</li><li>完整命令（推荐方式）： <ul><li>Linux/macOS：<code>curl -fsSL https://bun.com/install | bash</code></li><li>Windows：<code>powershell -c &quot;irm bun.sh/install.ps1 | iex&quot;</code></li><li>使用npm：<code>npm install -g bun</code></li><li>使用Homebrew：<code>brew tap oven-sh/bun &amp;&amp; brew install bun</code></li><li>使用Docker：<code>docker pull oven/bun</code></li></ul></li><li>成功标志：安装完成后显示Bun版本号</li><li>失败处理：检查网络连接，或尝试其他安装方式</li></ul><h3 id="步骤2-验证安装" tabindex="-1">步骤2：验证安装 <a class="header-anchor" href="#步骤2-验证安装" aria-label="Permalink to “步骤2：验证安装”">​</a></h3><ul><li>步骤目标：确认Bun已正确安装</li><li>执行位置：本机终端</li><li>完整命令：<code>bun -v</code></li><li>成功标志：显示Bun版本号</li><li>失败处理：重新安装或检查环境变量配置</li></ul><h3 id="步骤3-运行第一个脚本" tabindex="-1">步骤3：运行第一个脚本 <a class="header-anchor" href="#步骤3-运行第一个脚本" aria-label="Permalink to “步骤3：运行第一个脚本”">​</a></h3><ul><li>步骤目标：测试Bun运行时</li><li>执行位置：项目目录</li><li>完整命令：<code>bun run index.ts</code></li><li>成功标志：脚本正常执行</li><li>失败处理：检查脚本文件是否存在，语法是否正确</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ol><li>访问方式：终端命令</li><li>检查命令：<code>bun -v</code></li><li>预期返回：Bun版本号</li><li>页面特征（如适用）：无</li></ol><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p>现象：安装失败</p><ul><li>可能原因：网络问题、权限不足</li><li>解决步骤：检查网络连接，使用sudo（Linux/macOS）或以管理员身份运行（Windows）</li></ul></li><li><p>现象：执行命令提示&quot;command not found&quot;</p><ul><li>可能原因：环境变量未配置</li><li>解决步骤：重新打开终端，或手动添加Bun到PATH</li></ul></li><li><p>现象：运行现有Node.js项目出错</p><ul><li>可能原因：某些Node.js特性不完全兼容</li><li>解决步骤：查阅Bun官方文档，查看兼容性说明</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><ol><li>使用Docker：<code>docker run --rm --init --ulimit memlock=-1:-1 oven/bun</code></li><li>升级到最新版本：<code>bun upgrade</code></li><li>升级到canary版本：<code>bun upgrade --canary</code></li></ol><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>无，README中提供了完整的安装和使用说明。</p>',36)]))}const p=l(n,[["render",o]]);export{b as __pageData,p as default};
